// Parser la réponse OpenAI API
const input = $input.first().json;
let content;

try {
  const rawText = input.choices?.[0]?.message?.content || input.message?.content || input.text || input.content || JSON.stringify(input);
  let cleanText = rawText.trim();
  if (cleanText.startsWith('```json')) cleanText = cleanText.slice(7);
  if (cleanText.startsWith('```')) cleanText = cleanText.slice(3);
  if (cleanText.endsWith('```')) cleanText = cleanText.slice(0, -3);
  cleanText = cleanText.trim();
  content = JSON.parse(cleanText);
} catch (e) {
  return [{
    json: {
      error: true,
      message: "Erreur parsing réponse IA: " + e.message,
      raw: JSON.stringify(input).substring(0, 500)
    }
  }];
}

const theme = ((() => { try { return $('Sélecteur Thème').first()?.json; } catch(e) {} try { return $('Parser Webhook').first()?.json; } catch(e) {} return {}; })());

return [{
