// Formater le résultat LinkedIn
const resp = $input.first().json;
const statusCode = resp.statusCode || 200;
const headers = resp.headers || {};
const body = resp.body || resp;

// LinkedIn retourne le post URN dans le header x-restli-id ou dans le body
const postId = headers['x-restli-id'] || headers['x-linkedin-id'] || body.id || null;

return [{
  json: {
    platform: "linkedin",
    success: statusCode >= 200 && statusCode < 300,
    post_id: postId,
    error: statusCode >= 400 ? (body.message || body.serviceErrorCode || JSON.stringify(body).substring(0, 200)) : null
  }
}];

// Préparer la publication Instagram via Meta Graph API
const data = $input.first().json;
if (data.error) return [{ json: { platform: 'instagram', success: false, post_id: null, error: data.message } }];

const META_CONFIG = {
  PAGE_ACCESS_TOKEN: 'EAFntLfSxErEBQ11ZA6F73GQgStv9k4vBqZBWJUkCBACFfZChv1eFaR8acC6XoWDW1MySZBUyYxlZA5xIZChQbn0VoWW2Brh03BoJ8yZCVofahP5gmZAHsUFg0hvoPcbjEA3dorZBz37woXNsglFdYhIX2MXIBS9oKafGWL7M9Mnk0dFII6DRANtCjjnQXyVVoAgSllsAPKbs6idrLD5hexOwJSlNyNKwYaHtaUMjvShjb',
