};

const ig = data.instagram || {};
const hashtags = (ig.hashtags || []).map(h => h.startsWith('#') ? h : '#' + h).join(' ');

let caption;
if (data.source === 'manual') {
  // Manuel : utiliser le texte Facebook comme caption Instagram
  const fb = data.facebook || {};
  caption = fb.text || data.theme?.angle || '';
} else {
  // IA : utiliser le caption Instagram genere
  caption = (ig.caption || data.theme?.angle || '') + (hashtags ? '\n\n' + hashtags : '');
}

// Image : utiliser l image uploadee si disponible, sinon image par defaut
