  tenant_id: '00000000-0000-0000-0000-000000000001',
  platforms: {}
};

for (const item of items) {
  const r = item.json;
  if (r.platform) {
    summary.platforms[r.platform] = {
      success: !!r.success,
      post_id: r.post_id || null,
      error: r.error || null
    };
  }
}

return [{ json: summary }];

// Préparer les données pour insertion SQL
const data = $input.first().json;

function esc(val) {
  if (val === null || val === undefined) return 'NULL';
  return "'" + String(val).replace(/'/g, "''") + "'";
}

const platforms = Object.keys(data.platforms || {});
if (platforms.length === 0) platforms.push('facebook');
const rows = platforms.map(p => {
  const result = data.platforms?.[p] || {};
  const status = result.success ? 'publie' : 'erreur';
  const postId = result.post_id ? esc(result.post_id) : 'NULL';
  return `(gen_random_uuid(), ${esc(data.tenant_id)}::uuid, ${esc(p)}, ${esc(data.type)}, ${esc(data.sujet)}, ${esc(data.angle)}, NOW(), ${esc(status)}, ${postId}, NOW(), NOW())`;
});

const query = `INSERT INTO marketing_posts (id, tenant_id, plateforme, type, sujet, contenu_texte, date_publication, status, post_external_id, created_at, updated_at)
VALUES
  ${rows.join(',\n  ')}
ON CONFLICT DO NOTHING;`;

return [{ json: { query } }];

// Formater la notification Telegram (HTML mode — safe)
const data = ((() => { try { return $('Merger Résultats').first().json; } catch(e) { return $input.first().json; } })());

function esc(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const platformEmojis = { facebook: '📘', instagram: '📸', tiktok: '🎵', linkedin: '🔗' };

