  message += `${emoji} ${esc(platform)}: ${status}`;
  if (result.post_id) message += ` (ID: ${esc(result.post_id)})`;
  if (result.error) message += ` — ${esc(result.error)}`;
  message += '\n';
}

message += `\n<i>TalosPrimes — Votre gestion, automatisée.</i>`;

return [{
  json: {
    chatId: "6296082748",
    message: message
  }
}];

// Gestion d'erreur — notification Telegram (HTML mode — safe)
const error = $input.first().json;
function esc(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

const message = `❌ <b>ERREUR Marketing Workflow</b>\n\n`
  + `📅 ${new Date().toISOString().split('T')[0]}\n`
